const d = $input.first().json.body || $input.first().json;

const prompt = `You are Clio, InboundOS's lead qualification agent.

A new application just came in. Analyze it and return a JSON object with this exact shape:
{
  "qualification": "hot" | "warm" | "cold",
  "score": 0-100,
  "summary": "2-3 sentence plain English summary of who this person is and why they applied",
  "fit_analysis": "Why they are or aren't a fit for InboundOS consulting ($3K-$9K/mo)",
  "recommended_action": "book_call" | "nurture" | "disqualify",
  "action_reason": "One sentence on why",
  "personalized_reply": "A casual, warm 3-4 sentence reply MK can send to this person's Instagram DM or email. No pitch. Just human. Acknowledge their situation specifically."
}

Application Data:
- Name: ${d.name}
- Instagram: ${d.instagram}
- Business: ${d.business}
- Current Revenue: ${d.revenue}
- Main Blocker: ${d.blocker}${d.other_blocker ? ' — ' + d.other_blocker : ''}
- How long this has been a problem: ${d.duration}
- Investment readiness: ${d.investment}
- Why applying now: ${d.why_now}
- Source: ${d.source}

Qualification criteria for InboundOS:
- HOT: $3K+/mo revenue, ready to invest, specific blocker (no-leads or no-time), problem >6 months
- WARM: $1K-$3K/mo, or "need to check finances", or problem <6 months
- COLD: Pre-revenue OR "not financially ready" — these were auto-disqualified on form but may leak through

Return ONLY the JSON object. No markdown fences. No explanation.`;

return [{ json: { prompt, application_id: d.application_id, email: d.email, name: d.name, instagram: d.instagram } }];

const raw = $input.first().json.output || $input.first().json.result || $input.first().json.text || '';
let cleaned = raw.replace(/```json\n?/gi,'').replace(/```\n?/gi,'').trim();
let parsed;
try { parsed = JSON.parse(cleaned); } catch(e) { parsed = { qualification: 'warm', score: 50, summary: raw.slice(0,200), recommended_action: 'nurture', personalized_reply: '' }; }

const ctx = $('fa-build-prompt').item.json;
return [{ json: { ...parsed, application_id: ctx.application_id, email: ctx.email, name: ctx.name, instagram: ctx.instagram } }];
